class UserService {
  // 선언 시점에는 초기화 불가 — 생성자에서 초기화
  late String userId;
  late final String apiKey;  // final과 함께 사용 가능

  void initialize(String id, String key) {
    userId = id;    // ✅ 나중에 초기화
    apiKey = key;   // ✅ late final은 한 번만 초기화
  }

