void main() {
  int a = 17;
  int b = 5;

  print(a + b);   // 22  — 덧셈
  print(a - b);   // 12  — 뺄셈
  print(a * b);   // 85  — 곱셈
  print(a / b);   // 3.4 — 나눗셈 (결과: double)
  print(a ~/ b);  // 3   — 정수 나눗셈 (소수점 버림)
  print(a % b);   // 2   — 나머지 (모듈로)
  print(-a);      // -17 — 단항 부정
}

void main() {
  int x = 10;

  x += 5;   // x = x + 5  → 15
  x -= 3;   // x = x - 3  → 12
  x *= 2;   // x = x * 2  → 24
  x ~/= 5;  // x = x ~/ 5 → 4
  x %= 3;   // x = x % 3  → 1

  // 증감 연산자
  int y = 5;
  print(y++);  // 5 — 후위: 현재 값 반환 후 증가
  print(y);    // 6
  print(++y);  // 7 — 전위: 먼저 증가 후 반환
}

void main() {
  int a = 10;
  int b = 20;

  print(a == b);   // false — 같음
  print(a != b);   // true  — 다름
  print(a > b);    // false — 초과
  print(a < b);    // true  — 미만
  print(a >= b);   // false — 이상
  print(a <= b);   // true  — 이하
}

void main() {
  String s1 = 'hello';
  String s2 = 'hello';
  String s3 = s1;

  print(s1 == s2);          // true  — 값(내용) 비교
  print(identical(s1, s2)); // true  — 문자열 리터럴은 Dart가 동일 객체 재사용
  print(identical(s1, s3)); // true  — 같은 참조

  List<int> l1 = [1, 2, 3];
  List<int> l2 = [1, 2, 3];

  print(l1 == l2);          // false — List는 기본적으로 참조 비교
  print(identical(l1, l2)); // false — 서로 다른 객체
}

void main() {
  bool isLoggedIn = true;
  bool hasPermission = false;
  bool isPremium = true;

  // AND (&&) — 모두 true일 때 true
  print(isLoggedIn && hasPermission);    // false
  print(isLoggedIn && isPremium);        // true

  // OR (||) — 하나라도 true이면 true
  print(hasPermission || isPremium);     // true
  print(hasPermission || !isLoggedIn);   // false

  // NOT (!) — 반전
  print(!isLoggedIn);    // false
  print(!hasPermission); // true
}

