  // 전통 방식 — 중첩 null 체크
  String city1 = (user1.address != null && user1.address!.city != null)
      ? user1.address!.city!
      : '주소 미등록';

  // ?. 체이닝 — 간결함
  String city2 = user1.address?.city ?? '주소 미등록';  // 서울
  String city3 = user2.address?.city ?? '주소 미등록';  // 주소 미등록

