void describe(Object value) {
  switch (value) {
    case int n when n < 0:
      print('음수: $n');
    case int n:
      print('양의 정수: $n');
    case double d:
      print('실수: $d');
    case String s when s.isEmpty:
      print('빈 문자열');
    case String s:
      print('문자열: $s (길이: ${s.length})');
    case null:
      print('null 값');
    default:
      print('알 수 없는 타입');
  }
}

void main() {
