// ❌ 여러 구문 — Arrow function 불가, 일반 함수 사용
int addAndLog(int a, int b) {  // { } 필요
  print('$a + $b 계산 중');    // 구문 1
  return a + b;                // 구문 2
}

// ❌ if-else 문(Statement)은 Arrow function에 사용 불가
