// 팩토리얼 — n! = n × (n-1)!
int factorial(int n) {
  if (n <= 1) return 1;   // Base Case — 재귀 종료
  return n * factorial(n - 1);  // Recursive Case
}

// 피보나치
int fibonacci(int n) {
  if (n <= 1) return n;   // Base Case
  return fibonacci(n - 1) + fibonacci(n - 2);
}

void main() {
  print(factorial(5));    // 120  (5×4×3×2×1)
  print(factorial(0));    // 1
  print(fibonacci(8));    // 21   (0,1,1,2,3,5,8,13,21)
}

