> ```dart
> class Counter {
>   static int totalCreated = 0;
>   int _count = 0;
>
>   Counter() {
>     totalCreated++;
>   }
>
>   int get count => _count;
>   void increment() => _count++;
>   void reset() => _count = 0;
> }
>
> void main() {
>   var c1 = Counter()..increment()..increment();
>   var c2 = Counter()..increment();
>
>   print(c1.count);          // 2
>   print(c2.count);          // 1
>   print(Counter.totalCreated); // 2
> }
> ```

