  var priorities = [Priority.high, Priority.low, Priority.critical, Priority.medium];
  priorities.sort((a, b) => a.level.compareTo(b.level));
  for (var p in priorities) {
    print('${p.icon} ${p.displayName} (레벨: ${p.level})');
