// 3. 명세 위반 (API 계약 파기)
T first<T>(List<T> list) {
  if (list.isEmpty) throw StateError('빈 리스트에서 첫 요소 접근 불가');
  return list[0];
}

// ❌ 예외 던지기가 부적합한 경우

// 1. 자주 발생하는 정상 흐름
// Map에서 없는 키 조회 → null 반환이 자연스러움 (예외 X)
String? findUser(Map<String, String> db, String id) => db[id];

// 2. 단순 유효성 검사 결과 반환
