  }

  // eagerError: false — 모두 완료 후 첫 오류 전파
  try {
    await Future.wait([failFast(), slowSuccess()], eagerError: false);
  } catch (e) {
    print('대기 후 실패: $e');  // ≈ 500ms 후 출력 (slowSuccess 완료 대기)
  }
}

