// 문자열을 이메일인지 검사하고 싶다
String email = 'user@dart.dev';

// ❌ 방법 1: 유틸 함수 — 대상 객체가 인수로 묻힘
bool isValid = EmailUtils.isValid(email);

// ❌ 방법 2: 상속 — String은 final, 상속 불가
