// 검증 결과 — 성공이면 변환된 값, 실패면 오류 메시지
(T?, String?) validate<T>(
  String input,
  T? Function(String) parser,
  String Function(String) errorMsg,
) {
  final value = parser(input);
  return value != null ? (value, null) : (null, errorMsg(input));
}

// 사용
