  var curriedAdd = curry(add);
  var addFive    = curriedAdd(5);  // 첫 번째 인수 고정
  print(addFive(3));   // 8
  print(addFive(10));  // 15

  // 3인수 커링
  var curriedBetween = curry3(isBetween);
  var isTeen = curriedBetween(13)(19);  // 13 ~ 19
  print(isTeen(15));  // true
  print(isTeen(25));  // false

  // 부분 적용
