});

// ── Mock — 상호작용 검증까지 ──
// 사용 목적: "이 메서드가 정확히 이렇게 호출되었는가"를 검증

test('Mock 방식 — 상호작용 검증', () async {
  when(mockRepo.findById('u001'))
      .thenAnswer((_) async => User(id: 'u001', name: '홍', email: 'h@d.dev'));

  await service.getUser('u001');

