// Stack 클래스 (복습)
class Stack<E> {
  final List<E> _items = [];
  void push(E item) => _items.add(item);
  E pop() {
    if (_items.isEmpty) throw StateError('Stack이 비어 있습니다');
    return _items.removeLast();
  }
  E get peek {
    if (_items.isEmpty) throw StateError('Stack이 비어 있습니다');
    return _items.last;
  }
  bool get isEmpty => _items.isEmpty;
  int  get length  => _items.length;
}

